changeSet.sql:
CREATE TABLE qual_metrics
(
	id serial,
	name character varying (127) NOT NULL DEFAULT 'BASE',
	description text DEFAULT NULL,
	risk_model_id integer NOT NULL,
	ordinal integer DEFAULT 0,
	created_by_id integer DEFAULT NULL,
	updated_by_id integer DEFAULT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_qual_metrics PRIMARY KEY (id)
	, CONSTRAINT fk_qual_metrics_to_risk_models FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_qual_metrics_to_users_created FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_qual_metrics_to_users_updated FOREIGN KEY (updated_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_qual_metrics_name ON qual_metrics (name);
CREATE INDEX i_qual_metrics_risk_model ON qual_metrics (risk_model_id);
CREATE INDEX i_qual_metrics_risk_model_ordinal ON qual_metrics (risk_model_id, ordinal);
CREATE INDEX i_qual_metrics_created_by ON qual_metrics (created_by_id);
CREATE INDEX i_qual_metrics_updated_by ON qual_metrics (updated_by_id);
